  def debug_hook(module, args, output):
      print(f'Output type: {type(output)}')
      if isinstance(output, tuple):
          print(f'Tuple len: {len(output)}')
          for i, o in enumerate(output):
              if o is None:
                  print(f'  [{i}] None')
              elif hasattr(o, 'shape'):
                  print(f'  [{i}] tensor {o.shape}')
              else:
                  print(f'  [{i}] {type(o).__name__}')
                  if hasattr(o, 'key_cache'):
                      print(f'       key_cache[0] shape: {o.key_cache[-1].shape if o.key_cache else
  \"empty\"}')
                      print(f'       value_cache[0] shape: {o.value_cache[-1].shape if o.value_cache else
  \"empty\"}')
      raise StopIteration('got it')

